2359			"type":       eventType,
2360			"ts":         ts.UTC().Format(time.RFC3339Nano),
2361			"data":       data,
2362		}
2363		line, err := json.Marshal(entry)
2364		if err != nil {
2365			return
2366		}
2367		_, _ = sink.Write(line)
2368		_, _ = sink.Write([]byte("\n"))
2369	}

