213	// routingFacts is the harness/provider/model plus routing-intent metadata the
214	// most recent kind:routing, kind:escalation-summary, or
215	// execution-routing-intent event recorded for a bead. Used to fill in blanks
216	// on legacy attempts whose result.json predates those fields.
217	type routingFacts struct {
218		Harness               string
219		Provider              string
220		Model                 string
221		RoutingIntentSource   string
222		RequestedTier         string
223		SmartJustification    string
224		RejectedRoutePinCount int
225		RoutingIntentDegraded bool
226		RoutingIntentNote     string
227	}
