229	// loadRoutingEnrichment scans the bead store and indexes the most recent
230	// routing/escalation-summary/routing-intent facts per bead. Best-effort: a
231	// missing or unreadable bead store yields an empty map, never an error, since
232	// the loader still has authoritative data on each result.
233	func loadRoutingEnrichment(workingDir string) (map[string]routingFacts, error) {
234		store := bead.NewStore(filepath.Join(workingDir, ".ddx"))
235		beads, err := store.ReadAll()
236		if err != nil {
237			// Return an empty map so missing bead store does not abort
238			// metrics loading.
239			return map[string]routingFacts{}, nil
240		}
241		out := make(map[string]routingFacts, len(beads))
242		for _, b := range beads {
243			facts := routingFromExtra(b.Extra)
244			if facts.Harness == "" && facts.Provider == "" && facts.Model == "" &&
245				facts.RoutingIntentSource == "" && facts.RequestedTier == "" &&
246				facts.SmartJustification == "" && facts.RejectedRoutePinCount == 0 &&
247				!facts.RoutingIntentDegraded && facts.RoutingIntentNote == "" {
248				continue
249			}
250			out[b.ID] = facts
251		}
252		return out, nil
253	}
254	
255	// routingFromExtra walks bead.Extra["events"] in chronological order and
256	// returns the last kind:routing, kind:escalation-summary, or
257	// execution-routing-intent facts. The routing event carries resolved_provider
258	// / resolved_model, the escalation summary exposes a tiers_attempted list
259	// whose final entry is the winning tier, and the routing-intent event carries
260	// the durable bead-hint audit fields.
261	func routingFromExtra(extra map[string]any) routingFacts {
262		if extra == nil {
263			return routingFacts{}
264		}
265		raw, ok := extra["events"]
266		if !ok {
267			return routingFacts{}
268		}
269		items, ok := raw.([]any)
270		if !ok {
271			return routingFacts{}
272		}
273		type ev struct {
274			kind      string
275			body      string
276			createdAt time.Time
277		}
278		events := make([]ev, 0, len(items))
279		for _, item := range items {
280			m, ok := item.(map[string]any)
281			if !ok {
282				continue
283			}
284			kind, _ := m["kind"].(string)
285			if kind != "routing" && kind != "escalation-summary" && kind != "execution-routing-intent" {
286				continue
287			}
288			body, _ := m["body"].(string)
289			var createdAt time.Time
290			if v, ok := m["created_at"].(string); ok {
291				if t, err := time.Parse(time.RFC3339, v); err == nil {
292					createdAt = t
293				}
294			}
295			events = append(events, ev{kind: kind, body: body, createdAt: createdAt})
296		}
297		sort.SliceStable(events, func(i, j int) bool {
298			return events[i].createdAt.Before(events[j].createdAt)
299		})
300		var out routingFacts
301		for _, e := range events {
302			switch e.kind {
303			case "routing":
304				var body struct {
305					ResolvedProvider string `json:"resolved_provider"`
306					ResolvedModel    string `json:"resolved_model"`
307					RequestedHarness string `json:"requested_harness"`
308				}
309				if err := json.Unmarshal([]byte(e.body), &body); err != nil {
310					continue
311				}
312				if body.ResolvedProvider != "" {
313					out.Provider = body.ResolvedProvider
314				}
315				if body.ResolvedModel != "" {
316					out.Model = body.ResolvedModel
317				}
318				if body.RequestedHarness != "" {
319					out.Harness = body.RequestedHarness
320				}
321			case "escalation-summary":
322				var body struct {
323					WinningTier    string `json:"winning_tier"`
324					TiersAttempted []struct {
325						Tier    string `json:"tier"`
326						Harness string `json:"harness"`
327						Model   string `json:"model"`
328						Status  string `json:"status"`
329					} `json:"tiers_attempted"`
330				}
331				if err := json.Unmarshal([]byte(e.body), &body); err != nil {
332					continue
333				}
334				// Use the winning tier when one exists, else the last
335				// attempted tier.
336				pick := body.WinningTier
337				for _, t := range body.TiersAttempted {
338					if pick != "" && t.Tier == pick {
339						if t.Harness != "" {
340							out.Harness = t.Harness
341						}
342						if t.Model != "" {
343							out.Model = t.Model
344						}
345						break
346					}
347				}
348				if pick == "" && len(body.TiersAttempted) > 0 {
349					last := body.TiersAttempted[len(body.TiersAttempted)-1]
350					if last.Harness != "" {
351						out.Harness = last.Harness
352					}
353					if last.Model != "" {
354						out.Model = last.Model
355					}
356				}
357			case "execution-routing-intent":
358				var body struct {
359					RoutingIntentSource   string   `json:"routing_intent_source"`
360					RequestedTier         string   `json:"requested_tier"`
361					SmartJustification    string   `json:"smart_justification"`
362					ActualHarness         string   `json:"actual_harness"`
363					ActualProvider        string   `json:"actual_provider"`
364					ActualModel           string   `json:"actual_model"`
365					RoutingIntentDegraded bool     `json:"routing_intent_degraded"`
366					RoutingIntentNote     string   `json:"routing_intent_note"`
367					RejectedRoutePins     []string `json:"rejected_route_pins"`
368				}
369				if err := json.Unmarshal([]byte(e.body), &body); err != nil {
370					continue
371				}
372				if body.RoutingIntentSource != "" {
373					out.RoutingIntentSource = body.RoutingIntentSource
374				}
375				if body.RequestedTier != "" {
376					out.RequestedTier = body.RequestedTier
377				}
378				if body.SmartJustification != "" {
379					out.SmartJustification = body.SmartJustification
380				}
381				if body.ActualHarness != "" {
382					out.Harness = body.ActualHarness
383				}
384				if body.ActualProvider != "" {
385					out.Provider = body.ActualProvider
386				}
387				if body.ActualModel != "" {
388					out.Model = body.ActualModel
389				}
390				out.RoutingIntentDegraded = body.RoutingIntentDegraded
391				if body.RoutingIntentNote != "" {
392					out.RoutingIntentNote = body.RoutingIntentNote
393				}
394				out.RejectedRoutePinCount = len(body.RejectedRoutePins)
395			}
396		}
397		return out
398	}
