package agentmetrics

import (
	"bufio"
	"bytes"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

const (
	metricsSubdir         = ".ddx/metrics"
	AttemptsJSONLFilename = "attempts.jsonl"
	// SchemaVersion is the current schema_version written to every row.
	SchemaVersion = 1
)

// AttemptsRow is one row in .ddx/metrics/attempts.jsonl — the cold-tier,
// per-attempt denormalized metrics table. One row per bead execution attempt.
type AttemptsRow struct {
	SchemaVersion          int            `json:"schema_version"`
	AttemptID              string         `json:"attempt_id"`
	BeadID                 string         `json:"bead_id,omitempty"`
	SessionID              string         `json:"session_id,omitempty"`
	TSStart                time.Time      `json:"ts_start,omitempty"`
	TSEnd                  time.Time      `json:"ts_end,omitempty"`
	Model                  string         `json:"model,omitempty"`
	Harness                string         `json:"harness,omitempty"`
	Profile                string         `json:"profile,omitempty"`
	Provider               string         `json:"provider,omitempty"`
	PromptTemplateID       string         `json:"prompt_template_id,omitempty"`
	PromptTemplateHash     string         `json:"prompt_template_hash,omitempty"`
	SpecID                 string         `json:"spec_id,omitempty"`
	Outcome                string         `json:"outcome,omitempty"`
	ExitCode               int            `json:"exit_code"`
	CostUSD                float64        `json:"cost_usd,omitempty"`
	DurationMS             int64          `json:"duration_ms,omitempty"`
	InputTokens            int            `json:"input_tokens,omitempty"`
	OutputTokens           int            `json:"output_tokens,omitempty"`
	TotalTokens            int            `json:"total_tokens,omitempty"`
	ReviewVerdict          string         `json:"review_verdict,omitempty"`
	ReviewFindingsBySev    map[string]int `json:"review_finding_count_by_severity,omitempty"`
	LadderMinPowerInitial  int            `json:"ladder_min_power_initial,omitempty"`
	LadderMinPowerFinal    int            `json:"ladder_min_power_final,omitempty"`
	LadderStepsTaken       int            `json:"ladder_steps_taken,omitempty"`
}

// AttemptsJSONLPath returns the absolute path to .ddx/metrics/attempts.jsonl.
func AttemptsJSONLPath(projectRoot string) string {
	return filepath.Join(projectRoot, filepath.FromSlash(metricsSubdir), AttemptsJSONLFilename)
}

// AppendAttemptRow appends row to .ddx/metrics/attempts.jsonl using
// O_APPEND|O_CREATE for atomic single-writer appends. Always sets
// row.SchemaVersion to SchemaVersion (1). Silently returns nil when
// projectRoot or row.AttemptID is empty so callers can treat this as
// best-effort.
func AppendAttemptRow(projectRoot string, row AttemptsRow) error {
	if projectRoot == "" || row.AttemptID == "" {
		return nil
	}
	row.SchemaVersion = SchemaVersion
	dir := filepath.Join(projectRoot, filepath.FromSlash(metricsSubdir))
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("agentmetrics: mkdir %s: %w", dir, err)
	}
	data, err := json.Marshal(row)
	if err != nil {
		return fmt.Errorf("agentmetrics: marshal row: %w", err)
	}
	data = append(data, '\n')
	f, err := os.OpenFile(filepath.Join(dir, AttemptsJSONLFilename), os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
	if err != nil {
		return fmt.Errorf("agentmetrics: open attempts.jsonl: %w", err)
	}
	defer f.Close()
	_, err = f.Write(data)
	return err
}

// LoadAttemptsRows reads .ddx/metrics/attempts.jsonl and returns all valid
// rows. Returns nil, nil when the file does not exist.
func LoadAttemptsRows(projectRoot string) ([]AttemptsRow, error) {
	path := AttemptsJSONLPath(projectRoot)
	f, err := os.Open(path)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, fmt.Errorf("agentmetrics: open %s: %w", path, err)
	}
	defer f.Close()

	var rows []AttemptsRow
	sc := bufio.NewScanner(f)
	sc.Buffer(make([]byte, 1<<20), 1<<20)
	for sc.Scan() {
		line := bytes.TrimSpace(sc.Bytes())
		if len(line) == 0 {
			continue
		}
		var row AttemptsRow
		if err := json.Unmarshal(line, &row); err != nil {
			continue
		}
		rows = append(rows, row)
	}
	return rows, sc.Err()
}

// beadReader is the subset of bead.Store used by BackfillAttemptsFromBeadStore.
type beadReader interface {
	ReadAll() ([]bead.Bead, error)
	Events(id string) ([]bead.BeadEvent, error)
}

// BackfillAttemptsFromBeadStore reads all beads from store and emits one row
// per attempt found in kind:cost events. Rows already present in
// .ddx/metrics/attempts.jsonl (deduped by attempt_id) are skipped for
// idempotence. The bead store is the canonical source; .ddx/executions/ is
// NOT read by this function.
func BackfillAttemptsFromBeadStore(projectRoot string, store beadReader) error {
	existing, err := LoadAttemptsRows(projectRoot)
	if err != nil {
		return err
	}
	seen := make(map[string]bool, len(existing))
	for _, r := range existing {
		if r.AttemptID != "" {
			seen[r.AttemptID] = true
		}
	}

	beads, err := store.ReadAll()
	if err != nil {
		return fmt.Errorf("agentmetrics: backfill ReadAll: %w", err)
	}

	for _, b := range beads {
		events, err := store.Events(b.ID)
		if err != nil {
			continue
		}
		rows := rowsFromEvents(b, events)
		for _, row := range rows {
			if seen[row.AttemptID] {
				continue
			}
			if err := AppendAttemptRow(projectRoot, row); err != nil {
				return fmt.Errorf("agentmetrics: backfill append (bead=%s attempt=%s): %w", b.ID, row.AttemptID, err)
			}
			seen[row.AttemptID] = true
		}
	}
	return nil
}

// rowsFromEvents reconstructs AttemptsRows from a bead's event stream by
// joining kind:cost and kind:execution-routing-intent events on attempt_id.
// One row is emitted per unique attempt_id found in cost events (cost events
// are the anchor because they are only written when the agent actually ran).
func rowsFromEvents(b bead.Bead, events []bead.BeadEvent) []AttemptsRow {
	type costBody struct {
		AttemptID    string  `json:"attempt_id"`
		Provider     string  `json:"provider,omitempty"`
		Model        string  `json:"model,omitempty"`
		InputTokens  int     `json:"input_tokens"`
		OutputTokens int     `json:"output_tokens"`
		TotalTokens  int     `json:"total_tokens"`
		CostUSD      float64 `json:"cost_usd"`
		DurationMS   int     `json:"duration_ms"`
		ExitCode     int     `json:"exit_code"`
	}
	type intentBody struct {
		AttemptID   string `json:"attempt_id"`
		Harness     string `json:"actual_harness"`
		Provider    string `json:"actual_provider"`
		Model       string `json:"actual_model"`
		ActualPower int    `json:"actual_power"`
	}

	type attemptData struct {
		cost   *costBody
		intent *intentBody
		ts     time.Time
	}
	byAttempt := make(map[string]*attemptData)

	for _, ev := range events {
		switch ev.Kind {
		case "cost":
			var cb costBody
			if err := json.Unmarshal([]byte(ev.Body), &cb); err != nil || cb.AttemptID == "" {
				continue
			}
			d := byAttempt[cb.AttemptID]
			if d == nil {
				d = &attemptData{}
				byAttempt[cb.AttemptID] = d
			}
			d.cost = &cb
			if d.ts.IsZero() {
				d.ts = ev.CreatedAt
			}
		case "execution-routing-intent":
			var ib intentBody
			if err := json.Unmarshal([]byte(ev.Body), &ib); err != nil || ib.AttemptID == "" {
				continue
			}
			d := byAttempt[ib.AttemptID]
			if d == nil {
				d = &attemptData{}
				byAttempt[ib.AttemptID] = d
			}
			d.intent = &ib
		}
	}

	specID, _ := b.Extra["spec-id"].(string)
	var rows []AttemptsRow
	for attemptID, d := range byAttempt {
		if d.cost == nil {
			continue
		}
		row := AttemptsRow{
			SchemaVersion: SchemaVersion,
			AttemptID:     attemptID,
			BeadID:        b.ID,
			SpecID:        specID,
			CostUSD:       d.cost.CostUSD,
			DurationMS:    int64(d.cost.DurationMS),
			InputTokens:   d.cost.InputTokens,
			OutputTokens:  d.cost.OutputTokens,
			TotalTokens:   d.cost.TotalTokens,
			ExitCode:      d.cost.ExitCode,
			Model:         d.cost.Model,
			Provider:      d.cost.Provider,
		}
		if d.intent != nil {
			if d.intent.Harness != "" {
				row.Harness = d.intent.Harness
			}
			if row.Model == "" && d.intent.Model != "" {
				row.Model = d.intent.Model
			}
			if row.Provider == "" && d.intent.Provider != "" {
				row.Provider = d.intent.Provider
			}
			row.LadderMinPowerFinal = d.intent.ActualPower
		}
		if !d.ts.IsZero() {
			row.TSEnd = d.ts
		}
		rows = append(rows, row)
	}
	return rows
}

package agentmetrics

import (
	"encoding/json"
	"os"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// mockBeadReader implements beadReader for testing without a real store.
type mockBeadReader struct {
	beads  []bead.Bead
	events map[string][]bead.BeadEvent
}

func (m *mockBeadReader) ReadAll() ([]bead.Bead, error) {
