}

// TestMetrics_AppendRowOnFinalization asserts that AppendAttemptRow appends
// one row per call and that all expected fields are populated in the output.
func TestMetrics_AppendRowOnFinalization(t *testing.T) {
	dir := t.TempDir()
	now := time.Date(2026, 5, 10, 12, 0, 0, 0, time.UTC)

	row := AttemptsRow{
		AttemptID:             "20260510T120000-abc",
		BeadID:                "ddx-test-bead",
		SessionID:             "sess-123",
		TSStart:               now,
		TSEnd:                 now.Add(30 * time.Second),
		Model:                 "claude-sonnet-4-6",
		Harness:               "claude",
		Profile:               "smart",
		Provider:              "anthropic",
		SpecID:                "FEAT-001",
		Outcome:               "success",
