		t.Errorf("exit_code = %d, want %d", got.ExitCode, row.ExitCode)
	}
	if got.CostUSD != row.CostUSD {
		t.Errorf("cost_usd = %v, want %v", got.CostUSD, row.CostUSD)
	}
	if got.DurationMS != row.DurationMS {
		t.Errorf("duration_ms = %d, want %d", got.DurationMS, row.DurationMS)
