// TestMetrics_BackfillFromEvents asserts that BackfillAttemptsFromBeadStore
// emits correct rows from existing bead events (kind:cost + kind:execution-routing-intent).
func TestMetrics_BackfillFromEvents(t *testing.T) {
	dir := t.TempDir()
	now := time.Date(2026, 5, 10, 10, 0, 0, 0, time.UTC)

	costBody, _ := json.Marshal(map[string]any{
		"attempt_id":    "20260510T100000-fill",
		"provider":      "anthropic",
		"model":         "claude-sonnet-4-6",
		"input_tokens":  800,
		"output_tokens": 200,
		"total_tokens":  1000,
		"cost_usd":      0.33,
		"duration_ms":   15000,
		"exit_code":     0,
	})
	intentBody, _ := json.Marshal(map[string]any{
		"attempt_id":   "20260510T100000-fill",
		"actual_harness": "claude",
		"actual_provider": "anthropic",
		"actual_model":  "claude-sonnet-4-6",
		"actual_power":  60,
	})

	store := &mockBeadReader{
		beads: []bead.Bead{
			{
				ID:     "ddx-fill-bead",
				Title:  "backfill test",
				Status: "closed",
				Extra:  map[string]any{"spec-id": "FEAT-042"},
			},
		},
		events: map[string][]bead.BeadEvent{
			"ddx-fill-bead": {
				{Kind: "cost", Body: string(costBody), CreatedAt: now},
				{Kind: "execution-routing-intent", Body: string(intentBody), CreatedAt: now},
			},
		},
	}

	if err := BackfillAttemptsFromBeadStore(dir, store); err != nil {
		t.Fatalf("BackfillAttemptsFromBeadStore: %v", err)
	}

	rows, err := LoadAttemptsRows(dir)
	if err != nil {
		t.Fatalf("LoadAttemptsRows: %v", err)
	}
	if len(rows) != 1 {
		t.Fatalf("expected 1 row, got %d", len(rows))
	}

	got := rows[0]
	if got.AttemptID != "20260510T100000-fill" {
		t.Errorf("attempt_id = %q, want 20260510T100000-fill", got.AttemptID)
	}
	if got.BeadID != "ddx-fill-bead" {
		t.Errorf("bead_id = %q, want ddx-fill-bead", got.BeadID)
	}
	if got.SpecID != "FEAT-042" {
		t.Errorf("spec_id = %q, want FEAT-042", got.SpecID)
	}
	if got.Harness != "claude" {
		t.Errorf("harness = %q, want claude", got.Harness)
	}
	if got.Model != "claude-sonnet-4-6" {
		t.Errorf("model = %q, want claude-sonnet-4-6", got.Model)
	}
	if got.CostUSD != 0.33 {
		t.Errorf("cost_usd = %v, want 0.33", got.CostUSD)
	}
	if got.InputTokens != 800 {
		t.Errorf("input_tokens = %d, want 800", got.InputTokens)
	}
	if got.TotalTokens != 1000 {
		t.Errorf("total_tokens = %d, want 1000", got.TotalTokens)
	}
	if got.LadderMinPowerFinal != 60 {
		t.Errorf("ladder_min_power_final = %d, want 60", got.LadderMinPowerFinal)
	}
	if got.SchemaVersion != SchemaVersion {
		t.Errorf("schema_version = %d, want %d", got.SchemaVersion, SchemaVersion)
	}
}

// TestMetrics_BackfillIdempotent asserts that re-running backfill does not
// produce duplicate rows (deduplication by attempt_id).
func TestMetrics_BackfillIdempotent(t *testing.T) {
	dir := t.TempDir()

	costBody, _ := json.Marshal(map[string]any{
		"attempt_id":   "20260510T110000-idem",
		"cost_usd":     0.10,
		"duration_ms":  5000,
		"input_tokens": 100,
	})

	store := &mockBeadReader{
		beads: []bead.Bead{
			{ID: "ddx-idem-bead", Title: "idempotent", Status: "closed"},
		},
		events: map[string][]bead.BeadEvent{
			"ddx-idem-bead": {
				{Kind: "cost", Body: string(costBody)},
			},
		},
	}

	// Run backfill twice.
	for i := 0; i < 2; i++ {
		if err := BackfillAttemptsFromBeadStore(dir, store); err != nil {
			t.Fatalf("BackfillAttemptsFromBeadStore run %d: %v", i+1, err)
		}
	}

	rows, err := LoadAttemptsRows(dir)
	if err != nil {
		t.Fatalf("LoadAttemptsRows: %v", err)
	}
	if len(rows) != 1 {
		t.Fatalf("expected exactly 1 row after 2 backfill runs (idempotent), got %d", len(rows))
	}
}

// TestMetrics_SchemaVersion asserts that every row written by AppendAttemptRow
// carries schema_version == SchemaVersion (1) regardless of what the caller sets.
func TestMetrics_SchemaVersion(t *testing.T) {
	dir := t.TempDir()

	// Caller omits SchemaVersion (zero value).
	row := AttemptsRow{
		AttemptID: "20260510T130000-schema",
		BeadID:    "ddx-schema-test",
		Outcome:   "success",
	}
	if err := AppendAttemptRow(dir, row); err != nil {
		t.Fatalf("AppendAttemptRow: %v", err)
	}

	// Read raw JSONL to confirm the field is present.
	raw, err := os.ReadFile(AttemptsJSONLPath(dir))
	if err != nil {
		t.Fatalf("read attempts.jsonl: %v", err)
	}
	var parsed map[string]any
	if err := json.Unmarshal(raw[:len(raw)-1], &parsed); err != nil {
		t.Fatalf("parse row JSON: %v", err)
	}
	sv, ok := parsed["schema_version"]
	if !ok {
		t.Fatal("schema_version field missing from row")
	}
	// JSON numbers unmarshal to float64.
	if int(sv.(float64)) != SchemaVersion {
		t.Errorf("schema_version = %v, want %d", sv, SchemaVersion)
	}

	rows, err := LoadAttemptsRows(dir)
	if err != nil {
		t.Fatalf("LoadAttemptsRows: %v", err)
	}
	if len(rows) != 1 {
		t.Fatalf("expected 1 row, got %d", len(rows))
	}
	if rows[0].SchemaVersion != SchemaVersion {
		t.Errorf("deserialized schema_version = %d, want %d", rows[0].SchemaVersion, SchemaVersion)
	}
}

