package cmd

import (
	"fmt"
	"path/filepath"

	"github.com/DocumentDrivenDX/ddx/internal/agentmetrics"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/spf13/cobra"
)

// newWorkMetricsCommand creates "ddx work metrics" with backfill subcommand.
func (f *CommandFactory) newWorkMetricsCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "metrics",
		Short: "Work metrics utilities",
		Long:  "Utilities for managing .ddx/metrics/ cold-tier attempt data.",
		Run: func(cmd *cobra.Command, args []string) {
			_ = cmd.Help()
		},
	}
	cmd.AddCommand(f.newWorkMetricsBackfillCommand())
	return cmd
}

// newWorkMetricsBackfillCommand creates "ddx work metrics backfill".
func (f *CommandFactory) newWorkMetricsBackfillCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "backfill",
		Short: "Backfill .ddx/metrics/attempts.jsonl from existing bead events",
		Long: `Scan all beads and their events.jsonl sidecars and emit one row per
attempt found in kind:cost events. Rows already present in
.ddx/metrics/attempts.jsonl are skipped (idempotent by attempt_id).

This command reads only .ddx/attachments/ events — it does NOT read
.ddx/executions/ directories.`,
		Args: cobra.NoArgs,
		RunE: f.runWorkMetricsBackfill,
	}
	cmd.Flags().String("project", "", "Target project root (default: CWD git root)")
	return cmd
}

func (f *CommandFactory) runWorkMetricsBackfill(cmd *cobra.Command, args []string) error {
	projectFlag, _ := cmd.Flags().GetString("project")
	projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)

	store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
	if err := agentmetrics.BackfillAttemptsFromBeadStore(projectRoot, store); err != nil {
		return fmt.Errorf("metrics backfill: %w", err)
	}

	rows, err := agentmetrics.LoadAttemptsRows(projectRoot)
	if err != nil {
		return fmt.Errorf("metrics backfill: read result: %w", err)
	}
	fmt.Fprintf(cmd.OutOrStdout(), "backfill complete: %d rows in %s\n",
		len(rows), agentmetrics.AttemptsJSONLPath(projectRoot))
	return nil
}
